@using sv_8f0f7f41491e46ec9ad0d939bc8790a0.Services

<div class="card mb-4">
    <div class="card-header d-flex align-items-center gap-3">
        <div class="avatar-preview">
            @if (!string.IsNullOrWhiteSpace(AvatarUrl))
            {
                <img src="@AvatarUrl" alt="Avatar" class="rounded-circle" width="64" height="64" />
            }
            else
            {
                <div class="avatar-placeholder rounded-circle d-flex align-items-center justify-content-center">
                    <span class="fs-3">👤</span>
                </div>
            }
        </div>
        <div>
            <h5 class="mb-0">Profile Settings</h5>
            <small class="text-muted">Manage your personal information</small>
        </div>
    </div>
    <div class="card-body">
        <div class="mb-3">
            <label class="form-label fw-semibold">Display Name</label>
            <input type="text" class="form-control" @bind="DisplayName" @bind:event="oninput" />
        </div>
        <div class="mb-3">
            <label class="form-label fw-semibold">Email</label>
            <input type="email" class="form-control" @bind="Email" @bind:event="oninput" />
        </div>
        <div class="mb-3">
            <label class="form-label fw-semibold">Avatar URL</label>
            <input type="url" class="form-control" @bind="AvatarUrl" @bind:event="oninput" />
        </div>
        <div class="mb-3">
            <label class="form-label fw-semibold">Bio</label>
            <textarea class="form-control" rows="4" @bind="Bio" @bind:event="oninput"></textarea>
        </div>

        @if (!string.IsNullOrEmpty(StatusMessage))
        {
            <div class="alert @(IsError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                @StatusMessage
                <button type="button" class="btn-close" @onclick="() => StatusMessage = null"></button>
            </div>
        }

        <div class="d-flex gap-2">
            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@Saving">
                @if (Saving)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Save Changes
            </button>
            <button class="btn btn-outline-secondary" @onclick="Discard" disabled="@(!IsDirty)">
                Discard Changes
            </button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public UserProfile Profile { get; set; } = default!;

    [Parameter, EditorRequired]
    public EventCallback<UserProfile> OnSave { get; set; }

    private string DisplayName = "";
    private string Email = "";
    private string AvatarUrl = "";
    private string Bio = "";
    private string? StatusMessage;
    private bool IsError;
    private bool Saving;

    private bool IsDirty =>
        DisplayName != Profile.DisplayName ||
        Email != Profile.Email ||
        AvatarUrl != Profile.AvatarUrl ||
        Bio != Profile.Bio;

    protected override void OnParametersSet()
    {
        if (!IsDirty || string.IsNullOrEmpty(DisplayName))
        {
            LoadFromProfile();
        }
    }

    private void LoadFromProfile()
    {
        DisplayName = Profile.DisplayName;
        Email = Profile.Email;
        AvatarUrl = Profile.AvatarUrl;
        Bio = Profile.Bio;
    }

    private async Task SaveAsync()
    {
        Saving = true;
        StatusMessage = null;
        try
        {
            var updated = new UserProfile(DisplayName, Email, AvatarUrl, Bio);
            await OnSave.InvokeAsync(updated);
            StatusMessage = "Profile saved successfully!";
            IsError = false;
        }
        catch (Exception ex)
        {
            StatusMessage = $"Error saving profile: {ex.Message}";
            IsError = true;
        }
        finally
        {
            Saving = false;
        }
    }

    private void Discard()
    {
        LoadFromProfile();
        StatusMessage = null;
    }
}

.avatar-placeholder {
    width: 64px;
    height: 64px;
    background-color: var(--bs-tertiary-bg);
    border: 2px dashed var(--bs-border-color);
}

@using sv_8f0f7f41491e46ec9ad0d939bc8790a0.Services

<div class="card mb-4">
    <div class="card-header">
        <h5 class="mb-0">🔔 Notification Preferences</h5>
    </div>
    <div class="card-body">
        <div class="mb-4">
            <h6 class="fw-semibold mb-3">General</h6>
            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="emailNotif"
                       checked="@EmailNotifications"
                       @onchange="e => EmailNotifications = (bool)e.Value!" />
                <label class="form-check-label" for="emailNotif">Email Notifications</label>
            </div>
            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="pushNotif"
                       checked="@PushNotifications"
                       @onchange="e => PushNotifications = (bool)e.Value!" />
                <label class="form-check-label" for="pushNotif">Push Notifications</label>
            </div>
            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="weeklyDigest"
                       checked="@WeeklyDigest"
                       @onchange="e => WeeklyDigest = (bool)e.Value!" />
                <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
            </div>
        </div>

        <div class="mb-4">
            <h6 class="fw-semibold mb-3">Muted Channels</h6>
            @if (AllChannels.Count > 0)
            {
                @foreach (var channel in AllChannels)
                {
                    <div class="form-check mb-1">
                        <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                               checked="@MutedChannels.Contains(channel)"
                               @onchange="e => ToggleChannel(channel, (bool)e.Value!)" />
                        <label class="form-check-label" for="@($"ch-{channel}")">@channel</label>
                    </div>
                }
            }
            else
            {
                <p class="text-muted">No channels available.</p>
            }
        </div>

        @if (!string.IsNullOrEmpty(StatusMessage))
        {
            <div class="alert alert-success alert-dismissible fade show" role="alert">
                @StatusMessage
                <button type="button" class="btn-close" @onclick="() => StatusMessage = null"></button>
            </div>
        }

        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@Saving">
            @if (Saving)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Save Preferences
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public NotificationPrefs Prefs { get; set; } = default!;

    [Parameter, EditorRequired]
    public EventCallback<NotificationPrefs> OnSave { get; set; }

    [Parameter]
    public List<string> AllChannels { get; set; } = [];

    private bool EmailNotifications;
    private bool PushNotifications;
    private bool WeeklyDigest;
    private HashSet<string> MutedChannels = [];
    private string? StatusMessage;
    private bool Saving;
    private bool _initialized;

    protected override void OnParametersSet()
    {
        if (!_initialized)
        {
            EmailNotifications = Prefs.EmailNotifications;
            PushNotifications = Prefs.PushNotifications;
            WeeklyDigest = Prefs.WeeklyDigest;
            MutedChannels = [.. Prefs.MutedChannels];
            _initialized = true;
        }
    }

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted)
            MutedChannels.Add(channel);
        else
            MutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        Saving = true;
        StatusMessage = null;
        try
        {
            var updated = new NotificationPrefs(
                EmailNotifications, PushNotifications, WeeklyDigest,
                MutedChannels.ToList());
            await OnSave.InvokeAsync(updated);
            StatusMessage = "Preferences saved successfully!";
        }
        catch
        {
            StatusMessage = "Error saving preferences.";
        }
        finally
        {
            Saving = false;
        }
    }
}

