@using sv_8f0f7f41491e46ec9ad0d939bc8790a0.Services

<div class="card mb-4">
    <div class="card-header">
        <h5 class="mb-0">🎨 Appearance</h5>
    </div>
    <div class="card-body">
        <div class="row">
            <div class="col-md-6">
                <div class="mb-4">
                    <h6 class="fw-semibold mb-2">Theme</h6>
                    @foreach (var theme in new[] { "Light", "Dark", "System" })
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="theme"
                                   id="@($"theme-{theme}")"
                                   value="@theme"
                                   checked="@(Theme == theme)"
                                   @onchange="() => Theme = theme" />
                            <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                        </div>
                    }
                </div>

                <div class="mb-4">
                    <h6 class="fw-semibold mb-2">Font Size</h6>
                    @foreach (var size in new[] { "Small", "Medium", "Large" })
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="fontSize"
                                   id="@($"fs-{size}")"
                                   value="@size"
                                   checked="@(FontSize == size)"
                                   @onchange="() => FontSize = size" />
                            <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                        </div>
                    }
                </div>

                <div class="mb-4">
                    <h6 class="fw-semibold mb-2">Language</h6>
                    <select class="form-select" @bind="Language">
                        <option value="en">English</option>
                        <option value="es">Español</option>
                        <option value="fr">Français</option>
                        <option value="de">Deutsch</option>
                        <option value="ja">日本語</option>
                        <option value="zh">中文</option>
                    </select>
                </div>

                <div class="mb-4">
                    <h6 class="fw-semibold mb-2">Layout</h6>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" id="compactMode"
                               checked="@CompactMode"
                               @onchange="e => CompactMode = (bool)e.Value!" />
                        <label class="form-check-label" for="compactMode">Compact Mode</label>
                    </div>
                </div>
            </div>

            <div class="col-md-6">
                <h6 class="fw-semibold mb-2">Live Preview</h6>
                <div class="preview-area border rounded p-3 @GetPreviewClasses()">
                    <h6 style="@GetPreviewFontStyle()">Sample Heading</h6>
                    <p style="@GetPreviewFontStyle()">
                        This is how your content will look with the current settings.
                    </p>
                    <div class="d-flex gap-2 @(CompactMode ? "mt-1" : "mt-3")">
                        <button class="btn btn-sm btn-primary">Primary</button>
                        <button class="btn btn-sm btn-outline-secondary">Secondary</button>
                    </div>
                    <div class="@(CompactMode ? "mt-1" : "mt-3")">
                        <span class="badge bg-info me-1">Tag 1</span>
                        <span class="badge bg-warning me-1">Tag 2</span>
                        <span class="badge bg-success">Tag 3</span>
                    </div>
                </div>
            </div>
        </div>

        @if (!string.IsNullOrEmpty(StatusMessage))
        {
            <div class="alert alert-success alert-dismissible fade show mt-3" role="alert">
                @StatusMessage
                <button type="button" class="btn-close" @onclick="() => StatusMessage = null"></button>
            </div>
        }

        <button class="btn btn-primary mt-3" @onclick="SaveAsync" disabled="@Saving">
            @if (Saving)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Save
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public AppearanceSettings Appearance { get; set; } = default!;

    [Parameter, EditorRequired]
    public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string Theme = "Light";
    private string FontSize = "Medium";
    private string Language = "en";
    private bool CompactMode;
    private string? StatusMessage;
    private bool Saving;
    private bool _initialized;

    protected override void OnParametersSet()
    {
        if (!_initialized)
        {
            Theme = Appearance.Theme;
            FontSize = Appearance.FontSize;
            Language = Appearance.Language;
            CompactMode = Appearance.CompactMode;
            _initialized = true;
        }
    }

    private string GetPreviewClasses()
    {
        var bg = Theme switch
        {
            "Dark" => "bg-dark text-light",
            "Light" => "bg-white text-dark",
            _ => "bg-body text-body"
        };
        return $"{bg} {(CompactMode ? "p-2" : "p-3")}";
    }

    private string GetPreviewFontStyle() => FontSize switch
    {
        "Small" => "font-size: 0.85rem;",
        "Large" => "font-size: 1.15rem;",
        _ => "font-size: 1rem;"
    };

    private async Task SaveAsync()
    {
        Saving = true;
        StatusMessage = null;
        try
        {
            var updated = new AppearanceSettings(Theme, FontSize, Language, CompactMode);
            await OnSave.InvokeAsync(updated);
            StatusMessage = "Appearance saved successfully!";
        }
        catch
        {
            StatusMessage = "Error saving appearance settings.";
        }
        finally
        {
            Saving = false;
        }
    }
}

.preview-area {
    min-height: 180px;
    transition: all 0.2s ease;
}

