@page "/settings"
@using sv_8f0f7f41491e46ec9ad0d939bc8790a0.Services
@inject ISettingsService SettingsService
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-layout d-flex">
    <SettingsSidebar ActiveSection="@_activeSection"
                     OnSectionChanged="section => _activeSection = section" />

    <div class="settings-content flex-grow-1 p-4">
        @if (_loading)
        {
            <div class="d-flex justify-content-center align-items-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else if (_loadError is not null)
        {
            <div class="alert alert-danger" role="alert">
                <strong>Error loading settings:</strong> @_loadError
            </div>
        }
        else
        {
            @switch (_activeSection)
            {
                case "Profile":
                    <ProfileSection Profile="_profile!" OnSave="SaveProfileAsync" />
                    break;
                case "Notifications":
                    <NotificationsSection Prefs="_notificationPrefs!"
                                          AllChannels="_allChannels"
                                          OnSave="SaveNotificationPrefsAsync" />
                    break;
                case "Security":
                    <SecuritySection Settings="_securitySettings!"
                                     OnChangePassword="ChangePasswordAsync"
                                     OnRevokeSession="RevokeSessionAsync" />
                    break;
                case "Appearance":
                    <AppearanceSection Appearance="_appearance!"
                                       OnSave="SaveAppearanceAsync" />
                    break;
            }
        }
    </div>
</div>

@code {
    private string _activeSection = "Profile";
    private bool _loading = true;
    private string? _loadError;

    private UserProfile? _profile;
    private NotificationPrefs? _notificationPrefs;
    private SecuritySettings? _securitySettings;
    private AppearanceSettings? _appearance;

    // A superset of channels for the mute checklist UI
    private List<string> _allChannels = ["general", "announcements", "engineering", "design", "marketing", "random"];

    protected override async Task OnInitializedAsync()
    {
        try
        {
            var profileTask = SettingsService.GetProfileAsync();
            var notifsTask = SettingsService.GetNotificationPrefsAsync();
            var securityTask = SettingsService.GetSecuritySettingsAsync();
            var appearanceTask = SettingsService.GetAppearanceAsync();

            await Task.WhenAll(profileTask, notifsTask, securityTask, appearanceTask);

            _profile = profileTask.Result;
            _notificationPrefs = notifsTask.Result;
            _securitySettings = securityTask.Result;
            _appearance = appearanceTask.Result;
        }
        catch (Exception ex)
        {
            _loadError = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task SaveProfileAsync(UserProfile profile)
    {
        await SettingsService.SaveProfileAsync(profile);
        _profile = profile;
    }

    private async Task SaveNotificationPrefsAsync(NotificationPrefs prefs)
    {
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _notificationPrefs = prefs;
    }

    private async Task ChangePasswordAsync((string Current, string New) passwords)
    {
        await SettingsService.ChangePasswordAsync(passwords.Current, passwords.New);
    }

    private async Task RevokeSessionAsync(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        // Refresh security settings to reflect removed session
        _securitySettings = await SettingsService.GetSecuritySettingsAsync();
    }

    private async Task SaveAppearanceAsync(AppearanceSettings settings)
    {
        await SettingsService.SaveAppearanceAsync(settings);
        _appearance = settings;
    }
}

.settings-layout {
    min-height: calc(100vh - 100px);
    background: var(--bs-body-bg);
    border: 1px solid var(--bs-border-color);
    border-radius: 0.5rem;
    overflow: hidden;
}

.settings-content {
    max-width: 800px;
}

